ale: 1, duration: 50, ease: 'out(2.6)' }, '+=20' ) .add(arrow, { translate: '160px 10px', duration: 1200, ease: cubicBezier(0.474, 0.26,0.422,1) }, '+=150' ) .add(arrow, { scale: 0.75, duration: 150, ease: 'out(2.6)' }, '+=100' ) .call(() => setSlider(5900)) .add(arrow, { scale: 1, duration: 50, ease: 'out(2.6)' }, '+=20' ) .add(arrow, { opacity: 0, translate: '320px -150px', duration: 700, ease: 'in(2.6)' }, '+=100' ) .call(() => { setSlider(savedValue) }) }
